  ('LV-004', 'RTU Science and Innovation Centre', 'Riga Technical University (RTU)', 'Core Facility', 'LV', 'Riga', 56.951, 24.093, ARRAY['Advanced Manufacturing','Advanced Materials']::text[], ARRAY['Prototyping / Makerspace','Characterization & Metrology']::text[], 'Fee-for-service', '3D printing, CNC milling, laser cutting/engraving, large-format printing, mould making, materials testing', 'RTU''s Science and Innovation Centre offers a Product Development Unit providing prototyping, mould-making and materials-testing services to industry players and startups, alongside contract research.', 'rtu.lv', 'approved'),
  ('NO-001', 'Andøya Spaceport', 'Andøya Space AS', 'Space Launchpad', 'NO', 'Andenes', 69.2944, 16.0198, ARRAY['Space & Aerospace']::text[], ARRAY['Launchpad - Space','Characterization & Metrology']::text[], 'Fee-for-service', 'Orbital launch pad (LC-3), sounding-rocket pads, payload integration & environmental test facilities', 'Europe''s first operational mainland orbital spaceport, licensed Aug 2024; hosted Isar Aerospace''s Spectrum launch attempt (Mar 2025) and offers launch, payload-integration and environmental-test services to external customers.', 'andoyaspace.no', 'approved'),
  ('SE-001', 'Esrange Space Center', 'Swedish Space Corporation (SSC)', 'Space Launchpad', 'SE', 'Kiruna', 67.8897, 21.1042, ARRAY['Space & Aerospace']::text[], ARRAY['Launchpad - Space','Characterization & Metrology']::text[], 'Fee-for-service', 'Orbital launch complex, sounding-rocket & balloon pads, rocket engine/motor test stands, reusable-launcher testbed', 'Operational SSC-run rocket range; first continental-European orbital launch complex inaugurated 2023 (Firefly Alpha contracted), plus SubOrbital Express flights, engine testing and the Themis reusable-rocket testbed for commercial, institutional and academic customers.', 'sscspace.com', 'approved'),
  ('GB-083', 'SaxaVord Spaceport', 'SaxaVord Spaceport Ltd', 'Space Launchpad', 'GB', 'Unst, Shetland', 60.8181, -0.7925, ARRAY['Space & Aerospace']::text[], ARRAY['Launchpad - Space','Characterization & Metrology']::text[], 'Fee-for-service', 'Vertical launch pads (Lamba Ness), integration hangars, propellant storage, range tracking & telemetry, mission control', 'First fully licensed vertical spaceport in Western Europe (CAA licences 2023-24); licensed operators include Rocket Factory Augsburg (orbital) and Skyrora (suborbital), providing launch and integration services to external launch operators.', 'saxavord.com', 'approved'),
