  ('PT-001', 'Atlantic Spaceport (Malbusca Launch Centre, Santa Maria)', 'Atlantic Spaceport Consortium (ASC)', 'Space Launchpad', 'PT', 'Santa Maria, Azores', 36.9325, -25.07, ARRAY['Space & Aerospace']::text[], ARRAY['Launchpad - Space']::text[], 'Fee-for-service', 'Suborbital launch infrastructure (Malbusca), orbital capability planned; Santa Maria runway, port and ESA tracking station', 'Portugal''s first licensed spaceport (ANACOM operating licence, Aug 2025); demonstrated with GAMA test rockets in 2024, with external launch contracts signed with SpaceForest and INNOSPACE.', 'spaceport.pt', 'approved'),
  ('DE-031', 'JUNIQ - Jülich Unified Infrastructure for Quantum Computing', 'Forschungszentrum Jülich / JSC', 'Core Facility', 'DE', 'Jülich', 50.9067, 6.4072, ARRAY['Quantum']::text[], ARRAY['Dry Lab','Characterization & Metrology']::text[], 'Open user access (proposal)', 'Multiple QPUs & emulators (QSolid superconducting prototype, Pasqal); QC-as-a-Service via JuDoor', 'Manufacturer-independent public quantum-computing user facility: German and European users get cloud access to several quantum computers and emulators after creating a JuDoor account and applying for compute time.', 'fz-juelich.de', 'approved'),
